import { PageContainer } from '@ant-design/pro-layout';
import ProfileTable from './Profiles/ProfileTable'
import { useEffect, useState } from 'react';
import { useIntl, useModel } from '@umijs/max';
import { t } from '@/global';
import PersonalDetail from './PersonalDetail';

const AddressBooks: React.FC = () => {
  const [tabActiveKey, setTabActiveKey] = useState(localStorage.getItem('addressBookTabActiveKey') || 'personal');
  const { initialState } = useModel('@@initialState');
  const is_admin = initialState?.user?.is_admin;
  const intl = useIntl();

  const plain = (text: string, defaultMessage = '') => t(`pages.AddressBook.${text}`, true, defaultMessage || text, intl) as string;

  useEffect(() => {
    const list = getTabList();
    if (!list.map((tab) => tab.key).includes(tabActiveKey)) {
      setTabActiveKey('personal');
    }
  }, [is_admin]);

  const getTabList = () => {
    let tabs = [
      {
        tab: plain('Personal (My address book)'),
        key: 'personal',
      },
      {
        tab: plain('Shared'),
        key: 'shared',
      },
    ];
    return tabs;
  }

  return (
    <PageContainer
      tabList={getTabList()}
      tabActiveKey={tabActiveKey}
      onTabChange={(tab) => {
        setTabActiveKey(tab);
        localStorage.setItem('addressBookTabActiveKey', tab);
      }}
    >
      {tabActiveKey == "personal" && <PersonalDetail />}
      {tabActiveKey == "shared" && <ProfileTable />}
    </PageContainer>
  );
};

export default AddressBooks;
