import TagsCard from '../DetailComponents/TagsCard'
import DeviceTable from '../DetailComponents/DeviceTable';
import { useEffect, useRef, useState } from 'react';
import { getAbTags, getPersonalAb } from '@/services/api';
import { API } from '@/services/typings';
import { Col, Row, message } from 'antd';
import { t } from '@/global';
import { ActionType } from '@ant-design/pro-table';
import { ShareRule } from '../Profiles/RuleForm';

const AddressBookDetails: React.FC = () => {
  const [profile, setProfile] = useState<API.SharedAbProfile>();
  const [abTags, setAbTags] = useState<API.AbTag[]>([]);
  const deviceTableActionRef = useRef<ActionType>();
  const [selectedTags, setSelectedTags] = useState<string[]>([]);
  const [intersection, setIntersection] = useState(false);

  useEffect(() => {
    getTags();
  }, []);

  const getTags = async () => {
    try {
      let guid = (await getPersonalAb()).guid;
      let p: API.SharedAbProfile = {
        guid: guid,
        name: "My address book",
        owner: '',
        rule: ShareRule.FULL_CONTROL,
      };
      setProfile(p);
      setAbTags(await getAbTags(guid));
    } catch (error) {
      message.error(t(`Failed to get tags: ${error}`));
    }
  };

  return (
    <>
      <Row>
        <Col span={24}>
          {profile && <TagsCard personal={true} profile={profile} abTags={abTags} setAbTags={setAbTags} deviceTableActionRef={deviceTableActionRef}
            selectedTags={selectedTags} setSelectedTags={setSelectedTags} intersection={intersection} setIntersection={setIntersection} />}
        </Col>
      </Row>
      <Row style={{ marginTop: 20 }}>
        <Col span={24}>
          {profile && < DeviceTable personal={true} profile={profile} abTags={abTags} deviceTableActionRef={deviceTableActionRef}
            selectedTags={selectedTags} intersection={intersection} />}
        </Col>
      </Row>
    </>

  )
};

export default AddressBookDetails;
